  "extensionMigrationPrinciples": [
    {
      "principle": "Register all BatchImager workbench tools through one controlled Pi extension",
      "reason": "Avoid a split where some tools are Pi-native and others are customTools-only."
    },
    {
      "principle": "Keep BatchImager host executors for product actions",
      "reason": "Preflight, permission, image API invariants, workspace mutation, undo, and file safety are product responsibilities."
    },
    {
      "principle": "Move read/context tools first",
      "reason": "They are low-risk and validate whether Pi context/tool lifecycle reduces custom runtime glue."
    },
    {
      "principle": "Normalize result content before migration",
      "reason": "Every provider should receive the same content text and error semantics regardless of implementation path."
    },
    {
      "principle": "Do not expose user/project .pi extensions to override product tools by default",
      "reason": "Core product tools interact with user assets, paid APIs, and app state."
    }
  ],
  "testGuidance": [
    {
      "area": "Tool manifest consistency",
      "assertions": [
        "Every registered provider-visible tool appears in this database.",
        "Every database tool has name, surface, agentVisibleTo, risk, requiresPreflight, description, input, output, implementation.",
        "No duplicate visible tool names within one agent surface unless intentionally documented."
      ]
    },
    {
      "area": "Model-visible result consistency",
      "assertions": [
        "Success results include concise content text.",
        "Error results include Reason and suggestedNext when recovery is possible.",
        "LLM behavior tests do not depend on details-only data."
      ]
    },
    {
      "area": "Permission and preflight",
      "assertions": [
        "Non-read tools request permission unless explicitly preflight-only or documented safe.",
        "generate_image, run_batch_generation, and package_generated_images always create preflight before execution.",
        "Canceled preflight returns an error instructing the active provider not to retry unchanged."
      ]
    },
    {
      "area": "Image generation invariants",
      "assertions": [
        "Image API tools call the shared image executor.",
        "No tool defaults to square size.",
        "size is omitted unless user explicitly requested size/ratio/orientation."
      ]
    },
    {
      "area": "Controlled extension migration",
      "assertions": [
        "After migration, all provider-visible tools are registered through the controlled extension entry point.",
        "Executor implementation may differ, but tool schema and result content remain unchanged.",
        "Pi tool_call hooks cannot be bypassed by product tools."
      ]
    }
  ],
