  "reductionPrinciples": [
    {
      "name": "Pi 基础工具负责通用文件与命令",
      "rule": "Reading files, searching text, listing directories, and generic shell work should be handled by Pi read/grep/find/ls/bash with BatchImager policy wrappers, not by product-specific duplicate tools."
    },
    {
      "name": "BatchImager tools 只表达产品语义",
      "rule": "Keep tools that operate on sessions, generated records, reference images, preflight cards, memories, workspace ordering, package exports, or recovery-safe image generation."
    },
    {
      "name": "不要让 provider 直接猜内部存储",
      "rule": "If a result depends on project.sqlite, in-memory turn references, generated-record indexes, undo history, or UI state, keep a product tool instead of asking a provider to inspect files."
    },
    {
      "name": "删除要有替代路径",
      "rule": "A tool can be marked 建议删除 before code deletion, but actual deletion must wait until prompts, tests, and Pi policy wrappers make the replacement behavior safe and understandable."
    }
  ],
  "architectureModel": {
    "thesis": "右侧是 agent provider host；Esse 是第一种 provider。BatchImager 是任何 provider 都可以进入的图片工作台。BatchImager 需要 agent 才能获得智能协作能力，但 BatchImager 的产品语义应由 BatchImager 自己通过 capability API 拥有和暴露。",
    "actors": [
      {
        "name": "Agent provider registry",
        "role": "右侧 agent 宿主分发层。",
        "owns": "provider descriptor 列表、agent:send-message 到具体 provider runner 的分发、unsupported/unavailable provider 的统一错误。providerId 是稳定字符串协议，不再被 TypeScript 收窄到 esse；当前只注册 Esse。"
      },
      {
        "name": "Pi",
        "role": "agent runtime 与 tool 协议层。",
        "owns": "会话生命周期、tool schema、内置文件/搜索/bash 能力、extension 注册，以及模型和工具事件流。"
      },
      {
        "name": "Esse",
        "role": "通用协作 agent 人格和 shell。",
        "owns": "面向用户的推理、工具选择、对话连续性、记忆使用，以及跨工作台的一致 agent 行为；不内建 BatchImager 领域逻辑。"
      },
      {
        "name": "BatchImager",
        "role": "图片生成工作台和产品领域。",
        "owns": "项目、图片 session、生成记录、参考图、preflight 卡片、权限策略、图片 API 不变量、恢复、日志和 UI 状态。"
      },
      {
        "name": "Controlled Pi extension",
        "role": "Pi/provider 与工作台 capability provider 之间的受控适配层。",
        "owns": "模型可见的 tool 名称、schema、description、结果文本；执行时委托给 BatchImager capability API。"
      },
      {
        "name": "BatchImager Capability API",
        "role": "稳定产品能力接口，供 UI、Electron IPC、controlled extension 和可选 CLI 共用。",
        "owns": "只读产品查询和模型可见结果文本。Pi tool wrapper 只是调用入口，不是产品逻辑的源头。"
      },
      {
        "name": "BatchImager Workbench Action API",
        "role": "稳定产品写入接口，供任意 agent provider 的工具适配器共用。",
        "owns": "session、生成记录、排序、拆分/合并/复制、恢复和 undo 等工作台状态修改；所有 provider 只负责按协议请求动作。"
      },
      {
        "name": "Optional CLI",
        "role": "同一 capability API 之上的自动化/调试外壳。",
        "owns": "离线批处理、调试和 skill 调用；不承载需要实时 UI/preflight 交互的核心逻辑。"
      }
    ]
  },
  "designPrinciples": [
    {
      "name": "Provider 不内建工作台语义",
      "rule": "Agent providers should not own BatchImager concepts such as sessions, generated records, reference images, or preflight cards. Providers only see capabilities exposed by the current workbench."
    },
    {
      "name": "Provider 只适配，不拥有产品逻辑",
      "rule": "Each provider runner can choose its own runtime, prompt style, or tool protocol, but all BatchImager actions must still go through BatchImager workbench capabilities and safety policies."
    },
    {
      "name": "产品语义归工作台所有",
      "rule": "BatchImager owns its project model, mutations, invariants, and safety rules. Tool execution must call BatchImager capability APIs instead of duplicating product logic inside a provider or the extension wrapper."
    },
    {
      "name": "Pi 基础能力不重复造轮子",
      "rule": "Generic file read/search/list and shell execution belong to Pi read/grep/find/ls/bash with BatchImager policy wrappers. BatchImager should not expose duplicate project-file tools unless they add product semantics."
    },
    {
      "name": "Extension 是协议适配层",
      "rule": "Controlled Pi extension packages model-visible schemas and forwards calls to BatchImager capabilities. It should not become a second product service layer."
    },
    {
      "name": "Capability API 是真实接口",
      "rule": "The same capability/action API should be callable by UI/IPC, controlled Pi extension, and optional CLI where appropriate. This keeps behavior testable and avoids tool-only business logic."
    },
    {
      "name": "CLI 是可选外壳",
      "rule": "CLI is useful for debug, batch jobs, and skills, but UI-dependent flows such as preflight cards and live selection should stay API/event driven rather than CLI-first."
    },
    {
      "name": "模型可见契约必须稳定",
      "rule": "Whether a capability is backed by Pi built-in, controlled extension, Electron service, or CLI, providers should see stable names, descriptions, schemas, content text, and error wording."
    },
    {
      "name": "删除优先于迁移",
      "rule": "Before moving tools into extension form, remove duplicate generic tools and keep only product capabilities. A smaller tool world is easier for the active provider to reason about."
    }
  ],
